const QUESTIONS = [{"id": "2010-Q1", "year": 2010, "n": 1, "topic": "Economic Issues", "subs": ["Economic growth", "Unemployment"], "img": "2010_q01.png", "w": 1020, "h": 269, "ans": ["C"], "expl": "Growth raises output and the derived demand for labour, so increasing employment is the objective most compatible with economic growth. Price stability, external balance and environmental sustainability often conflict with rapid growth."}, {"id": "2010-Q2", "year": 2010, "n": 2, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2010_q02.png", "w": 1020, "h": 268, "ans": ["D"], "expl": "The National Competition Policy targets goods-and-services (product) markets by promoting competition. The labour, tax and financial options relate to factor or financial markets."}, {"id": "2010-Q3", "year": 2010, "n": 3, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2010_q03.png", "w": 1020, "h": 597, "ans": ["B"], "expl": "Current account = -40 (goods) -70 (services) -115 (income) +85 (transfers) = -$140bn. With a floating currency the capital and financial account must offset this with a $140bn surplus."}, {"id": "2010-Q4", "year": 2010, "n": 4, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2010_q04.png", "w": 1020, "h": 760, "ans": ["C"], "expl": "A minimum wage set above equilibrium (W1>We) creates an excess supply of labour - quantity supplied exceeds quantity demanded - so unemployment rises."}, {"id": "2010-Q5", "year": 2010, "n": 5, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2010_q05.png", "w": 1020, "h": 240, "ans": ["D"], "expl": "Cutting protection to manufacturing forces structural adjustment, displacing workers whose skills don't transfer. This structural unemployment raises the natural rate; interest-rate and spending changes affect only cyclical unemployment."}, {"id": "2010-Q6", "year": 2010, "n": 6, "topic": "Global Economy", "subs": ["Introduction to the global economy"], "img": "2010_q06.png", "w": 1020, "h": 268, "ans": ["C"], "expl": "The IMF's role is to promote international financial stability and provide emergency lending. The World Bank funds development and the WTO governs trade rules."}, {"id": "2010-Q7", "year": 2010, "n": 7, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2010_q07.png", "w": 1020, "h": 569, "ans": ["D"], "expl": "Contribution = weight x price rise. Clothing (20x20=400) outweighs housing (15x25=375), health (10x30=300) and food (30x10=300), so it adds most to inflation."}, {"id": "2010-Q8", "year": 2010, "n": 8, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2010_q08.png", "w": 1020, "h": 240, "ans": ["B"], "expl": "Lower labour costs and better infrastructure both reduce production costs, improving competitiveness. Higher interest rates, a dollar appreciation and higher inflation would each worsen it."}, {"id": "2010-Q9", "year": 2010, "n": 9, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2010_q09.png", "w": 1020, "h": 269, "ans": ["D"], "expl": "Removing tax concessions on city parking raises the private cost of driving, discouraging the activity that creates the negative externality. The other options encourage it."}, {"id": "2010-Q10", "year": 2010, "n": 10, "topic": "Economic Policies", "subs": ["Monetary policy", "Fiscal policy"], "img": "2010_q10.png", "w": 1020, "h": 747, "ans": ["A"], "expl": "The move from X to Y is a downturn, so stimulus is needed: the RBA buying securities injects cash and lowers rates, while an expansionary budget adds to demand."}, {"id": "2010-Q11", "year": 2010, "n": 11, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2010_q11.png", "w": 1020, "h": 381, "ans": ["D"], "expl": "Cutting discretionary spending reduces demand-pull inflation, while a depreciation raises the price of imports, adding to cost-push inflation."}, {"id": "2010-Q12", "year": 2010, "n": 12, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2010_q12.png", "w": 1020, "h": 489, "ans": ["D"], "expl": "The multiplier k = 1/MPS. MPS = change in S / change in Y = 100/200 = 0.5, so k = 1/0.5 = 2.0."}, {"id": "2010-Q13", "year": 2010, "n": 13, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2010_q13.png", "w": 1020, "h": 268, "ans": ["C"], "expl": "Selling new securities to fund a deficit increases demand for loanable funds, pushing up interest rates and crowding out private borrowing."}, {"id": "2010-Q14", "year": 2010, "n": 14, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2010_q14.png", "w": 1020, "h": 268, "ans": ["B"], "expl": "A larger budget deficit boosts aggregate demand (rightward), while cheaper labour lowers production costs, shifting aggregate supply right as well."}, {"id": "2010-Q15", "year": 2010, "n": 15, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2010_q15.png", "w": 1020, "h": 240, "ans": ["A"], "expl": "Public goods are non-excludable and non-rival, so once provided an extra user costs nothing - their marginal cost of provision is effectively zero, which is why markets under-provide them."}, {"id": "2010-Q16", "year": 2010, "n": 16, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2010_q16.png", "w": 1020, "h": 325, "ans": ["A", "D"], "expl": "A fixed rate imports the partner's conditions: fixing to a low-interest economy during a recession (A) or fixing below equilibrium during a boom (D) both support competitiveness or stimulus. NESA accepted A and D."}, {"id": "2010-Q17", "year": 2010, "n": 17, "topic": "Global Economy", "subs": ["Globalisation and economic development"], "img": "2010_q17.png", "w": 1020, "h": 442, "ans": ["C"], "expl": "A low HDI (0.3) indicates a less-developed economy, which typically has a higher population growth rate. Higher literacy, urbanisation and institutions go with a high HDI (Country B)."}, {"id": "2010-Q18", "year": 2010, "n": 18, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2010_q18.png", "w": 1020, "h": 596, "ans": ["B"], "expl": "The shift to services reflects greater financial and global integration plus lower protection exposing manufacturing to import competition, accelerating structural change."}, {"id": "2010-Q19", "year": 2010, "n": 19, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2010_q19.png", "w": 1020, "h": 843, "ans": ["A"], "expl": "The wealth curve bows further from the line of equality, so wealth has the higher Gini coefficient and is distributed more unequally than income."}, {"id": "2010-Q20", "year": 2010, "n": 20, "topic": "Global Economy", "subs": ["Protection"], "img": "2010_q20.png", "w": 1020, "h": 268, "ans": ["B"], "expl": "Raising the quota lets in more imports, increasing competition, so domestic producers' market share falls. A larger quota also lowers the domestic price and raises supply, ruling out the others."}, {"id": "2011-Q1", "year": 2011, "n": 1, "topic": "Global Economy", "subs": ["Globalisation and economic development"], "img": "2011_q01.png", "w": 1020, "h": 230, "ans": ["C"], "expl": "Higher oil prices raise transport and communication costs, making global trade and integration more expensive - slowing globalisation. The other options lower barriers."}, {"id": "2011-Q2", "year": 2011, "n": 2, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2011_q02.png", "w": 1020, "h": 229, "ans": ["A"], "expl": "Raising the minimum wage lifts the incomes of low-paid workers, narrowing the gap. Cutting benefits, decentralising wages or reducing education funding widen inequality."}, {"id": "2011-Q3", "year": 2011, "n": 3, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2011_q03.png", "w": 1020, "h": 256, "ans": ["C"], "expl": "The NAIRU is structural; increasing competition in factor markets improves flexibility and lowers structural unemployment. Demand-side fiscal or monetary policy affects only cyclical unemployment."}, {"id": "2011-Q4", "year": 2011, "n": 4, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2011_q04.png", "w": 1020, "h": 586, "ans": ["D"], "expl": "Injections (G+I+X = 85) equal withdrawals (S+T+M = 85), so the circular flow is in equilibrium."}, {"id": "2011-Q5", "year": 2011, "n": 5, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2011_q05.png", "w": 1020, "h": 792, "ans": ["A"], "expl": "Higher unit labour costs raise production costs, shifting aggregate supply left (AS0 to AS1). Lower inflation expectations or an appreciation would shift it right."}, {"id": "2011-Q6", "year": 2011, "n": 6, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2011_q06.png", "w": 1020, "h": 268, "ans": ["B"], "expl": "An appreciation makes Australian exports dearer abroad and a US recession cuts foreign demand - both reduce export volumes."}, {"id": "2011-Q7", "year": 2011, "n": 7, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2011_q07.png", "w": 1020, "h": 487, "ans": ["C"], "expl": "A fall in the terms of trade lowers export incomes; increasing government discretionary spending offsets the contractionary effect on the economy."}, {"id": "2011-Q8", "year": 2011, "n": 8, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2011_q08.png", "w": 1020, "h": 268, "ans": ["A"], "expl": "Inflation erodes the real value of money, so those on fixed incomes, bank deposits or pensions lose. Holders of real assets, whose values rise with inflation, benefit."}, {"id": "2011-Q9", "year": 2011, "n": 9, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2011_q09.png", "w": 1020, "h": 240, "ans": ["D"], "expl": "A higher Gini (more inequality) increases reliance on government welfare support - an economic cost. The other options are benefits or unrelated."}, {"id": "2011-Q10", "year": 2011, "n": 10, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2011_q10.png", "w": 1020, "h": 805, "ans": ["C"], "expl": "The supply of $A falls (S0 to S1), appreciating the dollar. A smaller net income deficit means fewer $A are sold to service foreign liabilities, reducing supply."}, {"id": "2011-Q11", "year": 2011, "n": 11, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2011_q11.png", "w": 1020, "h": 268, "ans": ["B"], "expl": "Higher relative interest rates attract foreign financial inflow seeking returns, raising demand for $A and appreciating it."}, {"id": "2011-Q12", "year": 2011, "n": 12, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2011_q12.png", "w": 1020, "h": 296, "ans": ["D"], "expl": "In an expansion incomes rise (progressive tax receipts increase) and unemployment falls (benefit payments decrease) - the automatic stabilisers at work."}, {"id": "2011-Q13", "year": 2011, "n": 13, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2011_q13.png", "w": 1020, "h": 481, "ans": ["C"], "expl": "MPC = change in C / change in Y = 90/150 = 0.6, so k = 2.5. A $40bn rise in investment raises income by 40x2.5 = $100bn, to $400bn."}, {"id": "2011-Q14", "year": 2011, "n": 14, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2011_q14.png", "w": 1020, "h": 269, "ans": ["B"], "expl": "A current account deficit is financed by foreign capital (raising liabilities), and a depreciation increases the $A value of foreign-currency debt (valuation effect)."}, {"id": "2011-Q15", "year": 2011, "n": 15, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2011_q15.png", "w": 1020, "h": 609, "ans": ["B"], "expl": "Current account = -15+5-50+5 = -$55bn. With the capital account +5, the financial account must be +$50bn to balance the accounts."}, {"id": "2011-Q16", "year": 2011, "n": 16, "topic": "Economic Policies", "subs": ["Monetary policy", "Fiscal policy"], "img": "2011_q16.png", "w": 1020, "h": 352, "ans": ["B"], "expl": "To dampen inflation, cut government spending (contractionary fiscal) and have the RBA sell securities to drain cash and raise rates (contractionary monetary)."}, {"id": "2011-Q17", "year": 2011, "n": 17, "topic": "Global Economy", "subs": ["Protection"], "img": "2011_q17.png", "w": 1020, "h": 864, "ans": ["D"], "expl": "Foreign producers receive the world price ($10). Imports fall from 300 (Qd400 minus Qs100) to 100 units after the tariff, cutting their revenue from $3000 to $1000 - a $2000 fall."}, {"id": "2011-Q18", "year": 2011, "n": 18, "topic": "Global Economy", "subs": ["Globalisation and economic development"], "img": "2011_q18.png", "w": 1020, "h": 551, "ans": ["D"], "expl": "Country A's higher HDI despite lower income per capita means its non-income components - life expectancy and education - must be higher than B's."}, {"id": "2011-Q19", "year": 2011, "n": 19, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2011_q19.png", "w": 1020, "h": 269, "ans": ["B"], "expl": "Borrowing from the Reserve Bank (monetary financing) expands the money supply directly, the most inflationary method. Selling securities or assets to the public does not add net money."}, {"id": "2011-Q20", "year": 2011, "n": 20, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2011_q20.png", "w": 1020, "h": 324, "ans": ["C"], "expl": "Adding social (external) costs to private costs shifts supply left, so equilibrium output falls and price rises - the efficient outcome once the externality is internalised."}, {"id": "2012-Q1", "year": 2012, "n": 1, "topic": "Global Economy", "subs": ["Trade, financial flows and foreign investment"], "img": "2012_q01.png", "w": 1020, "h": 240, "ans": ["B"], "expl": "The EU is a trading bloc - a group of economies with preferential trade arrangements. The UN, G20 and OECD are broader cooperation bodies, not trade blocs."}, {"id": "2012-Q2", "year": 2012, "n": 2, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2012_q02.png", "w": 1020, "h": 268, "ans": ["A"], "expl": "The Fair Work Act 2009 rationalised the award system into around 122 modern awards. It kept the safety net and national minimum wage."}, {"id": "2012-Q3", "year": 2012, "n": 3, "topic": "Global Economy", "subs": ["Globalisation and economic development"], "img": "2012_q03.png", "w": 1020, "h": 268, "ans": ["B"], "expl": "Development is associated with rising labour productivity through education, capital and technology. Agriculture's GDP share and reliance on aid typically fall."}, {"id": "2012-Q4", "year": 2012, "n": 4, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2012_q04.png", "w": 1020, "h": 268, "ans": ["A"], "expl": "The RBA's charter aims for price stability, full employment and the welfare of Australians - captured here by price stability and full employment."}, {"id": "2012-Q5", "year": 2012, "n": 5, "topic": "Economic Policies", "subs": ["Fiscal policy", "Monetary policy"], "img": "2012_q05.png", "w": 1020, "h": 495, "ans": ["A"], "expl": "With GDP falling and unemployment rising to 8%, boosting jobs needs stimulus on both fronts - expansionary fiscal and monetary policy."}, {"id": "2012-Q6", "year": 2012, "n": 6, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2012_q06.png", "w": 1020, "h": 583, "ans": ["C"], "expl": "Labour force = employed + unemployed. Year 1 = 900,000; Year 2 = 960,000 - an increase of 60,000."}, {"id": "2012-Q7", "year": 2012, "n": 7, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2012_q07.png", "w": 1020, "h": 621, "ans": ["B"], "expl": "Taxation ($60bn) exceeds government spending ($50bn), so the budget is in surplus. Injections and leakages are equal at $170bn, and exports exceed imports."}, {"id": "2012-Q8", "year": 2012, "n": 8, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2012_q08.png", "w": 1020, "h": 300, "ans": ["D"], "expl": "Rising unemployment lowers incomes (less income-tax revenue) and increases welfare (social security) payments - the automatic stabilisers."}, {"id": "2012-Q9", "year": 2012, "n": 9, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2012_q09.png", "w": 1020, "h": 299, "ans": ["D"], "expl": "Cheaper credit and lower returns on saving encourage spending and discourage saving, so consumption rises and the household saving rate falls."}, {"id": "2012-Q10", "year": 2012, "n": 10, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2012_q10.png", "w": 1020, "h": 332, "ans": ["C"], "expl": "Selling securities drains cash from Exchange Settlement accounts, tightening liquidity and pushing the cash rate up."}, {"id": "2012-Q11", "year": 2012, "n": 11, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2012_q11.png", "w": 1020, "h": 641, "ans": ["C"], "expl": "With a floating rate the current account (-$200bn, offsetting the +$200bn financial account) equals X-700+100-150+50, so exports = $500bn."}, {"id": "2012-Q12", "year": 2012, "n": 12, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2012_q12.png", "w": 1020, "h": 325, "ans": ["D"], "expl": "Efficient policy subsidises activities with positive externalities and taxes those with negative externalities, aligning private incentives with social welfare."}, {"id": "2012-Q13", "year": 2012, "n": 13, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2012_q13.png", "w": 1020, "h": 240, "ans": ["D"], "expl": "Public goods are non-excludable, so consumers can access them without paying directly - the free-rider problem that leads markets to under-provide them."}, {"id": "2012-Q14", "year": 2012, "n": 14, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2012_q14.png", "w": 1020, "h": 817, "ans": ["B"], "expl": "Higher labour productivity lowers unit costs and expands supply, shifting aggregate supply right (AS1 to AS2). Higher minimum wages, taxes or rates would shift it left."}, {"id": "2012-Q15", "year": 2012, "n": 15, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2012_q15.png", "w": 1020, "h": 498, "ans": ["A"], "expl": "Year 2 participation = 30/40 = 75% (down from 80%) and unemployment = 3/30 = 10% (down from 12.5%) - both lower."}, {"id": "2012-Q16", "year": 2012, "n": 16, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2012_q16.png", "w": 1020, "h": 269, "ans": ["A"], "expl": "A fall in national saving widens the savings-investment gap, which must be financed by foreign capital, increasing the current account deficit."}, {"id": "2012-Q17", "year": 2012, "n": 17, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2012_q17.png", "w": 1020, "h": 523, "ans": ["C"], "expl": "The $A buys more euro (0.7 to 0.8, an appreciation) but fewer US dollars (1.10 to 1.00, a depreciation)."}, {"id": "2012-Q18", "year": 2012, "n": 18, "topic": "Global Economy", "subs": ["Protection"], "img": "2012_q18.png", "w": 1020, "h": 780, "ans": ["A"], "expl": "The subsidy is the vertical distance between the original and subsidised supply curves - here $2 per towel (from $12 to the $10 subsidised equilibrium)."}, {"id": "2012-Q19", "year": 2012, "n": 19, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2012_q19.png", "w": 1020, "h": 268, "ans": ["C"], "expl": "k = change in Y / change in I = 20000/5000 = 4 = 1/(1-MPC), so MPC = 0.75."}, {"id": "2012-Q20", "year": 2012, "n": 20, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2012_q20.png", "w": 1020, "h": 287, "ans": ["D"], "expl": "A recession lowers income and spending on imports, and a depreciation makes imports dearer - both cut import volumes."}, {"id": "2013-Q1", "year": 2013, "n": 1, "topic": "Global Economy", "subs": ["Introduction to the global economy"], "img": "2013_q01.png", "w": 1020, "h": 276, "ans": ["A"], "expl": "The World Bank finances development projects such as infrastructure in developing countries. The IMF handles financial stability and the WTO trade rules."}, {"id": "2013-Q2", "year": 2013, "n": 2, "topic": "Global Economy", "subs": ["Protection"], "img": "2013_q02.png", "w": 1020, "h": 248, "ans": ["B"], "expl": "The most commonly cited justification for protection is safeguarding domestic jobs from cheaper imports."}, {"id": "2013-Q3", "year": 2013, "n": 3, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2013_q03.png", "w": 1020, "h": 722, "ans": ["C"], "expl": "Country A's Lorenz curve sits closer to the line of equality, indicating a more equal distribution - best explained by higher social welfare spending."}, {"id": "2013-Q4", "year": 2013, "n": 4, "topic": "Global Economy", "subs": ["Trade, financial flows and foreign investment"], "img": "2013_q04.png", "w": 1020, "h": 304, "ans": ["C"], "expl": "Preferential agreements can cause trade diversion - shifting imports from efficient non-members to less efficient members because of the tariff preference."}, {"id": "2013-Q5", "year": 2013, "n": 5, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2013_q05.png", "w": 1020, "h": 276, "ans": ["A"], "expl": "Cheaper child care lowers a barrier to job search, encouraging discouraged (hidden) workers to re-enter the labour force."}, {"id": "2013-Q6", "year": 2013, "n": 6, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2013_q06.png", "w": 1020, "h": 359, "ans": ["C"], "expl": "Cutting taxes and raising transfer payments both add to disposable income and demand - the most expansionary combination."}, {"id": "2013-Q7", "year": 2013, "n": 7, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2013_q07.png", "w": 1020, "h": 332, "ans": ["A"], "expl": "Higher compulsory superannuation raises employers' labour on-costs, feeding into cost-push (cost) inflation."}, {"id": "2013-Q8", "year": 2013, "n": 8, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2013_q08.png", "w": 1020, "h": 276, "ans": ["A"], "expl": "Retraining improves the skills and job-matching of the unemployed, lowering structural unemployment and the NAIRU."}, {"id": "2013-Q9", "year": 2013, "n": 9, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2013_q09.png", "w": 1020, "h": 359, "ans": ["C"], "expl": "Ignoring external costs, the market under-prices the good and over-produces it - price too low, output too high relative to the social optimum."}, {"id": "2013-Q10", "year": 2013, "n": 10, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2013_q10.png", "w": 1020, "h": 644, "ans": ["D"], "expl": "The current account = (100-120) -140 -40 = -$200bn, so the capital and financial account must show a $200bn surplus to balance."}, {"id": "2013-Q11", "year": 2013, "n": 11, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2013_q11.png", "w": 1020, "h": 276, "ans": ["A"], "expl": "The shift between mining and manufacturing causes structural (and related long-term and frictional) unemployment. Seasonal unemployment depends on the time of year, so it is unaffected."}, {"id": "2013-Q12", "year": 2013, "n": 12, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2013_q12.png", "w": 1020, "h": 248, "ans": ["B"], "expl": "Investing in more and better capital raises output per worker - the key driver of productivity. The other options reduce output or incentives."}, {"id": "2013-Q13", "year": 2013, "n": 13, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2013_q13.png", "w": 1020, "h": 359, "ans": ["C"], "expl": "Selling foreign currency (buying $A) and raising the cash rate both increase demand for the dollar, pushing its value up."}, {"id": "2013-Q14", "year": 2013, "n": 14, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2013_q14.png", "w": 1020, "h": 358, "ans": ["B"], "expl": "Lower interest rates lift consumption and investment, and a depreciation boosts net exports - both increase aggregate demand."}, {"id": "2013-Q15", "year": 2013, "n": 15, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2013_q15.png", "w": 1020, "h": 415, "ans": ["B"], "expl": "A smaller MPC means a smaller multiplier (k=1/(1-MPC)), so any given injection generates less income - equilibrium income falls."}, {"id": "2013-Q16", "year": 2013, "n": 16, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2013_q16.png", "w": 1020, "h": 432, "ans": ["D"], "expl": "Lower relative rates prompt investors to sell $A (supply rises) and the trade-weighted index falls as the dollar depreciates."}, {"id": "2013-Q17", "year": 2013, "n": 17, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2013_q17.png", "w": 1020, "h": 387, "ans": ["B"], "expl": "Selling Commonwealth Government Securities withdraws cash, reducing the money supply and tightening policy."}, {"id": "2013-Q18", "year": 2013, "n": 18, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2013_q18.png", "w": 1020, "h": 332, "ans": ["D"], "expl": "Headline CPI includes volatile items like petrol; a rise in world oil supply lowers petrol prices, dragging headline below the steadier underlying rate."}, {"id": "2013-Q19", "year": 2013, "n": 19, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2013_q19.png", "w": 1020, "h": 600, "ans": ["D"], "expl": "Export prices rose faster than import prices, so the terms of trade rose; but import volume grew more than export volume, so net export volume fell."}, {"id": "2013-Q20", "year": 2013, "n": 20, "topic": "Global Economy", "subs": ["Protection"], "img": "2013_q20.png", "w": 1020, "h": 807, "ans": ["D"], "expl": "Cutting the tariff lowers the domestic price, so local producers supply less (output falls); imports rise enough that tariff revenue ($5 x a larger import quantity) rises."}, {"id": "2014-Q1", "year": 2014, "n": 1, "topic": "Global Economy", "subs": ["Trade, financial flows and foreign investment"], "img": "2014_q01.png", "w": 1020, "h": 240, "ans": ["A"], "expl": "The EU is a trading bloc with preferential internal trade. The WTO, GATT and OECD are global governance or cooperation bodies."}, {"id": "2014-Q2", "year": 2014, "n": 2, "topic": "Global Economy", "subs": ["Introduction to the global economy"], "img": "2014_q02.png", "w": 1020, "h": 240, "ans": ["B"], "expl": "Australia belongs to the G20, the forum of major economies. It is not in the G8, NAFTA or ASEAN."}, {"id": "2014-Q3", "year": 2014, "n": 3, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2014_q03.png", "w": 1020, "h": 268, "ans": ["D"], "expl": "In a recession incomes fall, so income-tax receipts decrease. Transfer payments rise and GST receipts fall."}, {"id": "2014-Q4", "year": 2014, "n": 4, "topic": "Global Economy", "subs": ["Introduction to the global economy"], "img": "2014_q04.png", "w": 1020, "h": 268, "ans": ["B"], "expl": "The IMF provides emergency support during financial crises and balance-of-payments problems; trade disputes go to the WTO."}, {"id": "2014-Q5", "year": 2014, "n": 5, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2014_q05.png", "w": 1020, "h": 303, "ans": ["C"], "expl": "A floating rate moves with market forces, so a key disadvantage is greater exchange-rate volatility and uncertainty for traders and investors."}, {"id": "2014-Q6", "year": 2014, "n": 6, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2014_q06.png", "w": 1020, "h": 330, "ans": ["C"], "expl": "A positive externality is a spillover benefit to third parties - here, reduced congestion at the existing airport. The other options are costs or private effects."}, {"id": "2014-Q7", "year": 2014, "n": 7, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2014_q07.png", "w": 1020, "h": 404, "ans": ["B"], "expl": "Greater labour-market flexibility lowers structural unemployment and draws more people into work, so unemployment falls and participation rises."}, {"id": "2014-Q8", "year": 2014, "n": 8, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2014_q08.png", "w": 1020, "h": 511, "ans": ["C"], "expl": "The GDP deflator = nominal/real GDP. Prices rose about 2% while nominal GDP rose 5%, so the CPI rose by less than the change in nominal GDP."}, {"id": "2014-Q9", "year": 2014, "n": 9, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2014_q09.png", "w": 1020, "h": 346, "ans": ["D"], "expl": "Removing the subsidy shifts the supply of education left (higher cost to provide), raising equilibrium price and lowering quantity."}, {"id": "2014-Q10", "year": 2014, "n": 10, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2014_q10.png", "w": 1020, "h": 771, "ans": ["A"], "expl": "A depreciation results from lower demand for $A (shift left) and higher supply of $A (shift right); that combination guarantees the dollar falls."}, {"id": "2014-Q11", "year": 2014, "n": 11, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2014_q11.png", "w": 1020, "h": 347, "ans": ["D"], "expl": "Less competition gives firms market power to raise price and restrict output, so equilibrium price rises and quantity falls."}, {"id": "2014-Q12", "year": 2014, "n": 12, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2014_q12.png", "w": 1020, "h": 529, "ans": ["B"], "expl": "Inflation for 2013 = (156-150)/150 x 100 = 4%."}, {"id": "2014-Q13", "year": 2014, "n": 13, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2014_q13.png", "w": 1020, "h": 404, "ans": ["D"], "expl": "Foreign investment inflow is a credit on the capital and financial account, while the returns paid to foreign owners are a debit on the primary income account."}, {"id": "2014-Q14", "year": 2014, "n": 14, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2014_q14.png", "w": 1020, "h": 430, "ans": ["A"], "expl": "To ease policy the RBA buys securities from banks, so banks hold fewer government securities and more cash in Exchange Settlement accounts."}, {"id": "2014-Q15", "year": 2014, "n": 15, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2014_q15.png", "w": 1020, "h": 808, "ans": ["A"], "expl": "A lower top marginal tax rate and higher business profits both concentrate income at the top, increasing inequality (the Lorenz curve bows further from equality)."}, {"id": "2014-Q16", "year": 2014, "n": 16, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2014_q16.png", "w": 1020, "h": 568, "ans": ["C"], "expl": "Current account = 10-20-5 = -$15bn; with the capital account +$1bn, the financial account must be a $14bn surplus to balance."}, {"id": "2014-Q17", "year": 2014, "n": 17, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2014_q17.png", "w": 1020, "h": 375, "ans": ["D"], "expl": "Raising the youth minimum wage while the adult rate is unchanged makes young workers relatively dearer, cutting demand for them and raising youth unemployment."}, {"id": "2014-Q18", "year": 2014, "n": 18, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2014_q18.png", "w": 1020, "h": 1070, "ans": ["A"], "expl": "MPC = 40/50 = 0.8, so k = 5. To lift income by $100m, exports rose 100/5 = $20m."}, {"id": "2014-Q19", "year": 2014, "n": 19, "topic": "Global Economy", "subs": ["Protection"], "img": "2014_q19.png", "w": 1020, "h": 353, "ans": ["B"], "expl": "Cutting the tariff from $15 to $10 lowers the domestic price from $25 to $20; the change in tariff revenue (tariff x import quantity) is $200 million."}, {"id": "2014-Q20", "year": 2014, "n": 20, "topic": "Global Economy", "subs": ["Protection"], "img": "2014_q20.png", "w": 1020, "h": 380, "ans": ["C"], "expl": "A $5 tariff lifts the price to $15, where the gap between domestic demand and supply - the equivalent quota - is 40 million units."}, {"id": "2015-Q1", "year": 2015, "n": 1, "topic": "Global Economy", "subs": ["Protection"], "img": "2015_q01.png", "w": 1020, "h": 356, "ans": ["A"], "expl": "Selling below cost of production is dumping; a tariff imposed to counter it is an anti-dumping measure."}, {"id": "2015-Q2", "year": 2015, "n": 2, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2015_q02.png", "w": 1020, "h": 244, "ans": ["B"], "expl": "Monetary policy can be changed quickly by the RBA board, giving it the shortest implementation lag; fiscal and micro reform need budgets or legislation."}, {"id": "2015-Q3", "year": 2015, "n": 3, "topic": "Global Economy", "subs": ["Trade, financial flows and foreign investment"], "img": "2015_q03.png", "w": 1020, "h": 243, "ans": ["D"], "expl": "Investment by transnational corporations in developing economies adds to global output; higher rates, more protection or migration to poorer nations tend to reduce it."}, {"id": "2015-Q4", "year": 2015, "n": 4, "topic": "Global Economy", "subs": ["Trade, financial flows and foreign investment"], "img": "2015_q04.png", "w": 1020, "h": 266, "ans": ["D"], "expl": "A downside of foreign direct investment is the greater power of transnational corporations over host-government regulation; the other options are benefits."}, {"id": "2015-Q5", "year": 2015, "n": 5, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2015_q05.png", "w": 1020, "h": 300, "ans": ["A"], "expl": "Aid that funds capital works (schools) is a capital transfer, recorded as a debit in the capital account when Australia provides it."}, {"id": "2015-Q6", "year": 2015, "n": 6, "topic": "Australia & Global Economy", "subs": ["Protection in Australia"], "img": "2015_q06.png", "w": 1020, "h": 416, "ans": ["C"], "expl": "Reducing the import quota exposes local firms to competition, driving efficiency, while a subsidy can assist them to invest and lift competitiveness."}, {"id": "2015-Q7", "year": 2015, "n": 7, "topic": "Economic Policies", "subs": ["Fiscal policy", "Monetary policy"], "img": "2015_q07.png", "w": 1020, "h": 548, "ans": ["D"], "expl": "Strong growth with inflation above the 2-3% target signals overheating, so tighten on both fronts - contractionary fiscal and monetary policy."}, {"id": "2015-Q8", "year": 2015, "n": 8, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2015_q08.png", "w": 1020, "h": 272, "ans": ["A"], "expl": "Progressive income tax automatically takes a bigger share as incomes rise in an upswing, restraining demand without new legislation - an automatic stabiliser."}, {"id": "2015-Q9", "year": 2015, "n": 9, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2015_q09.png", "w": 1020, "h": 795, "ans": ["D"], "expl": "Higher foreign interest rates draw financial flows out of Australia, lowering demand for $A and depreciating it."}, {"id": "2015-Q10", "year": 2015, "n": 10, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2015_q10.png", "w": 1020, "h": 586, "ans": ["B"], "expl": "Rising import prices with steady export prices lower the terms of trade, and the higher trade-weighted index (appreciation) reduces international competitiveness."}, {"id": "2015-Q11", "year": 2015, "n": 11, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2015_q11.png", "w": 1020, "h": 356, "ans": ["C"], "expl": "Childcare subsidies for low-income earners and a higher top marginal tax rate both redistribute toward the poor, lowering the Gini coefficient."}, {"id": "2015-Q12", "year": 2015, "n": 12, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2015_q12.png", "w": 1020, "h": 356, "ans": ["A"], "expl": "Cleaner recycling creates spillover benefits and lowers social (environmental) costs - a positive externality."}, {"id": "2015-Q13", "year": 2015, "n": 13, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2015_q13.png", "w": 1020, "h": 694, "ans": ["C"], "expl": "Supply-side (efficiency) policy shifts aggregate supply right, raising equilibrium output while easing price pressure."}, {"id": "2015-Q14", "year": 2015, "n": 14, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2015_q14.png", "w": 1020, "h": 638, "ans": ["D"], "expl": "Rising consumer confidence lifts hiring (lower unemployment), while higher school retention keeps more people out of the labour force (lower participation)."}, {"id": "2015-Q15", "year": 2015, "n": 15, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2015_q15.png", "w": 1020, "h": 272, "ans": ["A"], "expl": "A rise in net foreign liabilities increases servicing costs (net income outflow), worsening the structural component of the current account deficit; export swings are cyclical."}, {"id": "2015-Q16", "year": 2015, "n": 16, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2015_q16.png", "w": 1020, "h": 567, "ans": ["B"], "expl": "MPS = 100/500 = 0.2, so k = 5. To raise income by $1000, investment must rise 1000/5 = $200."}, {"id": "2015-Q17", "year": 2015, "n": 17, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2015_q17.png", "w": 1020, "h": 394, "ans": ["C"], "expl": "Buying securities lowers the cash rate, which depreciates the $A and stimulates activity, so GDP rises."}, {"id": "2015-Q18", "year": 2015, "n": 18, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2015_q18.png", "w": 1020, "h": 563, "ans": ["A"], "expl": "Nominal GDP rose from 1000 to 1100 (+10%), but prices also rose 10%, so real GDP growth is 0%."}, {"id": "2015-Q19", "year": 2015, "n": 19, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2015_q19.png", "w": 1020, "h": 671, "ans": ["B"], "expl": "Floods spike volatile food prices, lifting headline inflation, while microeconomic reform improves efficiency and lowers underlying inflation."}, {"id": "2015-Q20", "year": 2015, "n": 20, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2015_q20.png", "w": 1020, "h": 771, "ans": ["B"], "expl": "Current account = 50-200+25 = -$125bn and the financial account = 5+50+10+45 = $110bn, so the capital account must be a $15bn surplus to balance."}, {"id": "2016-Q1", "year": 2016, "n": 1, "topic": "Global Economy", "subs": ["Introduction to the global economy"], "img": "2016_q01.png", "w": 1020, "h": 240, "ans": ["A"], "expl": "The EU includes a monetary union (the euro area) sharing one currency. APEC, ASEAN and NAFTA are trade groupings, not monetary unions."}, {"id": "2016-Q2", "year": 2016, "n": 2, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2016_q02.png", "w": 1020, "h": 240, "ans": ["B"], "expl": "Monetary policy (the cash rate) is the main tool for managing inflation in Australia."}, {"id": "2016-Q3", "year": 2016, "n": 3, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2016_q03.png", "w": 1020, "h": 240, "ans": ["C"], "expl": "A bigger surplus needs revenue up and spending down - increase taxation and reduce government spending."}, {"id": "2016-Q4", "year": 2016, "n": 4, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2016_q04.png", "w": 1020, "h": 269, "ans": ["B"], "expl": "Weaker demand from trading partners cuts exports and output, raising Australia's unemployment. Growth, export demand and the CPI would fall."}, {"id": "2016-Q5", "year": 2016, "n": 5, "topic": "Australia & Global Economy", "subs": ["Protection in Australia"], "img": "2016_q05.png", "w": 1020, "h": 296, "ans": ["D"], "expl": "Lower tariffs cut the domestic price, redistributing income away from protected local producers toward importers and consumers."}, {"id": "2016-Q6", "year": 2016, "n": 6, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2016_q06.png", "w": 1020, "h": 268, "ans": ["B"], "expl": "The GST is regressive, taking a larger share of low incomes, so raising it increases inequality (a higher Gini coefficient)."}, {"id": "2016-Q7", "year": 2016, "n": 7, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2016_q07.png", "w": 1020, "h": 297, "ans": ["C"], "expl": "Frictional unemployment is short-term, between jobs - the worker moving from a closed business to starting a new one. The others are cyclical, structural or underemployment."}, {"id": "2016-Q8", "year": 2016, "n": 8, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2016_q08.png", "w": 1020, "h": 745, "ans": ["A"], "expl": "Redistributing income toward lower-income earners, who have a higher marginal propensity to consume, raises aggregate consumption."}, {"id": "2016-Q9", "year": 2016, "n": 9, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2016_q09.png", "w": 1020, "h": 414, "ans": ["B"], "expl": "A higher retirement age keeps older people in the labour force (higher participation) and earning taxable income (higher tax revenue)."}, {"id": "2016-Q10", "year": 2016, "n": 10, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2016_q10.png", "w": 1020, "h": 652, "ans": ["D"], "expl": "Decentralised wage bargaining links pay to productivity, encouraging firms to hire more - shifting the labour demand curve right."}, {"id": "2016-Q11", "year": 2016, "n": 11, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2016_q11.png", "w": 1020, "h": 353, "ans": ["C"], "expl": "Borrowing offshore raises net foreign debt; the interest paid abroad adds to the net primary income deficit, widening the current account deficit."}, {"id": "2016-Q12", "year": 2016, "n": 12, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2016_q12.png", "w": 1020, "h": 380, "ans": ["C"], "expl": "Higher interest rates reward savers, redistributing income toward those with a high marginal propensity to save."}, {"id": "2016-Q13", "year": 2016, "n": 13, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2016_q13.png", "w": 1020, "h": 325, "ans": ["D"], "expl": "Loan principal repayments are financial flows; receiving a repayment is a credit in the capital and financial account."}, {"id": "2016-Q14", "year": 2016, "n": 14, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2016_q14.png", "w": 1020, "h": 306, "ans": ["A"], "expl": "Lower demand for exports and higher supply both push export prices down relative to import prices, lowering the terms of trade."}, {"id": "2016-Q15", "year": 2016, "n": 15, "topic": "Global Economy", "subs": ["Globalisation and economic development"], "img": "2016_q15.png", "w": 1020, "h": 268, "ans": ["D"], "expl": "Recognising overseas qualifications improves access to skilled labour and global integration, helping an emerging Australian industry grow."}, {"id": "2016-Q16", "year": 2016, "n": 16, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2016_q16.png", "w": 1020, "h": 516, "ans": ["D"], "expl": "Real GDP rises (nominal +50% versus prices +10%), but population also grew 50%, so real GDP per capita falls - the HDI most likely decreases."}, {"id": "2016-Q17", "year": 2016, "n": 17, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2016_q17.png", "w": 1020, "h": 269, "ans": ["C"], "expl": "Infrastructure investment raises productivity and labour mobility, lowering structural unemployment and the NAIRU."}, {"id": "2016-Q18", "year": 2016, "n": 18, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2016_q18.png", "w": 1020, "h": 583, "ans": ["C"], "expl": "The $A appreciated (0.70 to 0.75), lifting purchasing power abroad, while positive domestic inflation erodes purchasing power at home."}, {"id": "2016-Q19", "year": 2016, "n": 19, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2016_q19.png", "w": 1020, "h": 558, "ans": ["A"], "expl": "Net foreign debt = 600-150 = $450bn; net foreign equity = 100-250 = -$150bn; net foreign liabilities = 450-150 = $300bn."}, {"id": "2016-Q20", "year": 2016, "n": 20, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2016_q20.png", "w": 1020, "h": 240, "ans": ["A"], "expl": "Congestion means travel times vary with usage, so one person's use reduces another's - the road is rival, failing the non-rival test for a pure public good."}, {"id": "2017-Q1", "year": 2017, "n": 1, "topic": "Global Economy", "subs": ["Trade, financial flows and foreign investment"], "img": "2017_q01.png", "w": 1020, "h": 240, "ans": ["D"], "expl": "Freer international labour mobility lets transnational corporations source labour globally; trade barriers and financial restrictions hinder them."}, {"id": "2017-Q2", "year": 2017, "n": 2, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2017_q02.png", "w": 1020, "h": 240, "ans": ["D"], "expl": "A pure public good is non-excludable (users can't be stopped) and non-rival (one person's use doesn't reduce another's)."}, {"id": "2017-Q3", "year": 2017, "n": 3, "topic": "Economic Policies", "subs": ["Limitations of economic policy"], "img": "2017_q03.png", "w": 1020, "h": 240, "ans": ["A"], "expl": "Fiscal policy needs budget and legislative processes, giving it a longer implementation lag than monetary policy, which the RBA can change promptly."}, {"id": "2017-Q4", "year": 2017, "n": 4, "topic": "Economic Policies", "subs": ["Fiscal policy", "Monetary policy"], "img": "2017_q04.png", "w": 1020, "h": 325, "ans": ["A"], "expl": "With spare capacity - high unemployment and below-target inflation - both fiscal and monetary policy should be expansionary."}, {"id": "2017-Q5", "year": 2017, "n": 5, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2017_q05.png", "w": 1020, "h": 268, "ans": ["B"], "expl": "Greater aggregate supply reflects lower costs and higher productivity, improving international competitiveness. Inflation, more spending or a dearer dollar would worsen it."}, {"id": "2017-Q6", "year": 2017, "n": 6, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2017_q06.png", "w": 1020, "h": 268, "ans": ["B"], "expl": "A market-based measure uses price signals - tradeable pollution permits - rather than direct regulation, fines or treaties."}, {"id": "2017-Q7", "year": 2017, "n": 7, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2017_q07.png", "w": 1020, "h": 269, "ans": ["C"], "expl": "Company tax receipts fall automatically when profits drop in a downturn - a cyclical (business-cycle) effect. The others are discretionary rate changes."}, {"id": "2017-Q8", "year": 2017, "n": 8, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2017_q08.png", "w": 1020, "h": 268, "ans": ["A"], "expl": "Government borrowing in the domestic money market competes for funds, putting upward pressure on interest rates (crowding out)."}, {"id": "2017-Q9", "year": 2017, "n": 9, "topic": "Global Economy", "subs": ["Protection"], "img": "2017_q09.png", "w": 1020, "h": 324, "ans": ["B"], "expl": "A smaller quota restricts imports, reducing supply and raising the domestic price; domestic firms then produce more and gain market share."}, {"id": "2017-Q10", "year": 2017, "n": 10, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2017_q10.png", "w": 1020, "h": 269, "ans": ["A"], "expl": "The National Minimum Wage applies to all legally employed adult workers, regardless of union membership, award or enterprise agreement."}, {"id": "2017-Q11", "year": 2017, "n": 11, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2017_q11.png", "w": 1020, "h": 380, "ans": ["C"], "expl": "The terms of trade = export prices / import prices. A fall from 115 to 105 means import prices rose relative to export prices."}, {"id": "2017-Q12", "year": 2017, "n": 12, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2017_q12.png", "w": 1020, "h": 380, "ans": ["B"], "expl": "Wages (returns to labour) dominate household income, followed by transfer payments, then returns to land and capital, then enterprise."}, {"id": "2017-Q13", "year": 2017, "n": 13, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2017_q13.png", "w": 1020, "h": 325, "ans": ["A"], "expl": "Weaker demand for Australian exports lowers demand for $A, depreciating it."}, {"id": "2017-Q14", "year": 2017, "n": 14, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2017_q14.png", "w": 1020, "h": 402, "ans": ["D"], "expl": "Leakages (M+T+S = 125) exceed injections (G+I+X = 115), so the economy is contracting."}, {"id": "2017-Q15", "year": 2017, "n": 15, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2017_q15.png", "w": 1020, "h": 575, "ans": ["B"], "expl": "In Year 2 the labour force = 3+2 = 5m; unemployment = 2/5 = 40% and participation = 5/8 = 62.5%."}, {"id": "2017-Q16", "year": 2017, "n": 16, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2017_q16.png", "w": 1020, "h": 485, "ans": ["C"], "expl": "Prices rise 5% then about 4.8% - still rising, but at a decreasing rate."}, {"id": "2017-Q17", "year": 2017, "n": 17, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2017_q17.png", "w": 1020, "h": 662, "ans": ["C"], "expl": "With a floating rate the accounts must sum to zero. Year 1 leaves a $5bn gap and Year 2 a $10bn gap, so net errors and omissions are larger in Year 2."}, {"id": "2017-Q18", "year": 2017, "n": 18, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2017_q18.png", "w": 1020, "h": 325, "ans": ["B"], "expl": "Only one borrower can use the book at a time, so it is rival - failing the non-rivalry condition of a public good."}, {"id": "2017-Q19", "year": 2017, "n": 19, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2017_q19.png", "w": 1020, "h": 602, "ans": ["D"], "expl": "k=2.5 gives MPC=0.6, so C=100+0.6Y. At Y=1000, Z=700; when C=1300, X=2000."}, {"id": "2017-Q20", "year": 2017, "n": 20, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2017_q20.png", "w": 1020, "h": 352, "ans": ["B"], "expl": "The $A fell from US$0.80 to US$0.75 (a depreciation), making Australian exports cheaper for US buyers in 2020."}, {"id": "2018-Q1", "year": 2018, "n": 1, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2018_q01.png", "w": 1020, "h": 248, "ans": ["C"], "expl": "Decentralised bargaining links wages to enterprise performance, aiming to lift labour productivity."}, {"id": "2018-Q2", "year": 2018, "n": 2, "topic": "Global Economy", "subs": ["Introduction to the global economy"], "img": "2018_q02.png", "w": 1020, "h": 276, "ans": ["A"], "expl": "The World Bank finances development infrastructure such as bridges; the IMF handles financial stability and the WTO trade rules."}, {"id": "2018-Q3", "year": 2018, "n": 3, "topic": "Global Economy", "subs": ["Trade, financial flows and foreign investment"], "img": "2018_q03.png", "w": 1020, "h": 331, "ans": ["A"], "expl": "A free trade agreement with B diverts trade toward B and away from C - classic trade diversion."}, {"id": "2018-Q4", "year": 2018, "n": 4, "topic": "Global Economy", "subs": ["Trade, financial flows and foreign investment"], "img": "2018_q04.png", "w": 1020, "h": 247, "ans": ["D"], "expl": "A lower company tax rate raises after-tax returns, attracting more foreign direct investment."}, {"id": "2018-Q5", "year": 2018, "n": 5, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2018_q05.png", "w": 1020, "h": 398, "ans": ["D"], "expl": "Buying foreign currency (selling $A) and cutting the interest rate both depreciate the currency, making exports more competitive."}, {"id": "2018-Q6", "year": 2018, "n": 6, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2018_q06.png", "w": 1020, "h": 332, "ans": ["B"], "expl": "More users slowing the service shows rivalry - one person's use reduces what is available to others (congestion)."}, {"id": "2018-Q7", "year": 2018, "n": 7, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2018_q07.png", "w": 1020, "h": 419, "ans": ["A"], "expl": "Higher US rates attract funds to the US, raising demand for $US and depreciating the $A."}, {"id": "2018-Q8", "year": 2018, "n": 8, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2018_q08.png", "w": 1020, "h": 388, "ans": ["C"], "expl": "Country A is more equal; cutting its top marginal tax rate would increase inequality, moving its Lorenz curve toward B's."}, {"id": "2018-Q9", "year": 2018, "n": 9, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2018_q09.png", "w": 1020, "h": 398, "ans": ["A"], "expl": "Buying the foreign company is a capital outflow (debit financial account); the dividend received is primary income (credit current account)."}, {"id": "2018-Q10", "year": 2018, "n": 10, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2018_q10.png", "w": 1020, "h": 332, "ans": ["D"], "expl": "Unfair-dismissal protection sits in the Fair Work Act's general provisions, not the ten National Employment Standards, so it is not guaranteed by the NES."}, {"id": "2018-Q11", "year": 2018, "n": 11, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2018_q11.png", "w": 1020, "h": 342, "ans": ["D"], "expl": "Moving from a $10bn surplus to a $5bn deficit is the largest swing toward stimulus - an expansionary fiscal stance."}, {"id": "2018-Q12", "year": 2018, "n": 12, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2018_q12.png", "w": 1020, "h": 332, "ans": ["C"], "expl": "Most private-sector firms operate across state borders, so a single national industrial-relations system reduces inconsistency and compliance costs."}, {"id": "2018-Q13", "year": 2018, "n": 13, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2018_q13.png", "w": 1020, "h": 247, "ans": ["B"], "expl": "Well-designed regulation (competition or safety rules) can correct market failure and raise efficiency - not all regulation reduces it."}, {"id": "2018-Q14", "year": 2018, "n": 14, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2018_q14.png", "w": 1020, "h": 331, "ans": ["C"], "expl": "Most people earn wages, and many small or family businesses make little or no profit, so returns to enterprise are a small share of household income."}, {"id": "2018-Q15", "year": 2018, "n": 15, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2018_q15.png", "w": 1020, "h": 667, "ans": ["B"], "expl": "Higher interest rates discourage spending and encourage saving, lowering consumption at each income level."}, {"id": "2018-Q16", "year": 2018, "n": 16, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2018_q16.png", "w": 1020, "h": 615, "ans": ["D"], "expl": "Stronger demand for this economy's exports relative to its imports raises both the terms of trade and the currency (trade-weighted index)."}, {"id": "2018-Q17", "year": 2018, "n": 17, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2018_q17.png", "w": 1020, "h": 332, "ans": ["B"], "expl": "More global oil supply cuts petrol prices, pulling headline inflation below the steadier underlying rate."}, {"id": "2018-Q18", "year": 2018, "n": 18, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2018_q18.png", "w": 1020, "h": 601, "ans": ["B"], "expl": "With MPC 0.8 the multiplier is 5, so $1bn extra spending raises income by $5bn - exactly the gap to full employment, leaving unemployment at the NAIRU."}, {"id": "2018-Q19", "year": 2018, "n": 19, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2018_q19.png", "w": 1020, "h": 388, "ans": ["C"], "expl": "The union's shared currency is weaker than booming country B would have alone, making it cheaper for foreign firms to buy assets in country B."}, {"id": "2018-Q20", "year": 2018, "n": 20, "topic": "Global Economy", "subs": ["Protection"], "img": "2018_q20.png", "w": 1020, "h": 810, "ans": ["C"], "expl": "Government revenue only arises under a tariff, and foreign producers gaining revenue means imports resumed - so a zero quota (no imports) was replaced by a $2 tariff."}, {"id": "2019-Q1", "year": 2019, "n": 1, "topic": "Global Economy", "subs": ["Globalisation and economic development"], "img": "2019_q01.png", "w": 1020, "h": 240, "ans": ["A"], "expl": "Globalisation spreads production across countries - an international division of labour. It lowers protection and inefficiency, not raises them."}, {"id": "2019-Q2", "year": 2019, "n": 2, "topic": "Global Economy", "subs": ["Introduction to the global economy"], "img": "2019_q02.png", "w": 1020, "h": 240, "ans": ["D"], "expl": "The G20 is a forum where major economies coordinate economic policy; it is not a trading bloc, free-trade agreement or monetary union."}, {"id": "2019-Q3", "year": 2019, "n": 3, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2019_q03.png", "w": 1020, "h": 268, "ans": ["C"], "expl": "A stronger $A lowers the local-currency cost of servicing foreign-currency debt - a benefit of appreciation."}, {"id": "2019-Q4", "year": 2019, "n": 4, "topic": "Economic Policies", "subs": ["Limitations of economic policy"], "img": "2019_q04.png", "w": 1020, "h": 241, "ans": ["B"], "expl": "Monetary policy is set by the independent RBA, insulating it from the political constraints that affect fiscal, labour-market and microeconomic policy."}, {"id": "2019-Q5", "year": 2019, "n": 5, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2019_q05.png", "w": 1020, "h": 240, "ans": ["B"], "expl": "Parents re-entering the workforce increases the share of working-age people in the labour force - a higher participation rate."}, {"id": "2019-Q6", "year": 2019, "n": 6, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2019_q06.png", "w": 1020, "h": 240, "ans": ["A"], "expl": "Higher interest rates raise borrowing costs, cutting consumer spending and slowing economic growth."}, {"id": "2019-Q7", "year": 2019, "n": 7, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2019_q07.png", "w": 1020, "h": 240, "ans": ["B"], "expl": "Low unemployment tightens the labour market and tends to push wages up, so it is not a cause of low wage growth."}, {"id": "2019-Q8", "year": 2019, "n": 8, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2019_q08.png", "w": 1020, "h": 241, "ans": ["A"], "expl": "Mining and services are Australia's two largest export earners."}, {"id": "2019-Q9", "year": 2019, "n": 9, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2019_q09.png", "w": 1020, "h": 488, "ans": ["C"], "expl": "Imports (350) exceed exports (250), so the trade balance is in deficit; but injections (1000) exceed leakages (850), so the economy is growing."}, {"id": "2019-Q10", "year": 2019, "n": 10, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2019_q10.png", "w": 1020, "h": 297, "ans": ["D"], "expl": "A lower cash rate reduces returns on cash and cheapens credit, lifting demand for and prices of assets."}, {"id": "2019-Q11", "year": 2019, "n": 11, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2019_q11.png", "w": 1020, "h": 785, "ans": ["B"], "expl": "Raising the progressive top tax rate and cutting the regressive GST both reduce inequality, moving the Lorenz curve toward equality."}, {"id": "2019-Q12", "year": 2019, "n": 12, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2019_q12.png", "w": 1020, "h": 513, "ans": ["D"], "expl": "Net foreign liabilities = debt $900bn + equity $100bn = $1000bn; as a share of $1800bn GDP that is 55.6%."}, {"id": "2019-Q13", "year": 2019, "n": 13, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2019_q13.png", "w": 1020, "h": 324, "ans": ["A"], "expl": "A positive inflation rate (2%) means prices are still increasing on average, just more slowly than before - disinflation, not deflation."}, {"id": "2019-Q14", "year": 2019, "n": 14, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2019_q14.png", "w": 1020, "h": 529, "ans": ["A"], "expl": "Labour force = 50% of 10m = 5m; employed = 5m x 90% = 4.5m; part-time = 4.5m - 4m full-time = 500,000."}, {"id": "2019-Q15", "year": 2019, "n": 15, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2019_q15.png", "w": 1020, "h": 517, "ans": ["B"], "expl": "MPS = 50/200 = 0.25, so k = 4. A $35bn rise in investment adds 35x4 = $140bn, lifting income to $590bn."}, {"id": "2019-Q16", "year": 2019, "n": 16, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2019_q16.png", "w": 1020, "h": 296, "ans": ["A"], "expl": "Lowering the tax-free threshold is a deliberate (discretionary) tax increase that withdraws demand - contractionary. The other options are automatic (cyclical)."}, {"id": "2019-Q17", "year": 2019, "n": 17, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2019_q17.png", "w": 1020, "h": 419, "ans": ["C"], "expl": "Aid for capital works is a debit on the capital account; pensions received from abroad are current transfers - a credit in secondary income."}, {"id": "2019-Q18", "year": 2019, "n": 18, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2019_q18.png", "w": 1020, "h": 942, "ans": ["B"], "expl": "A higher terms of trade and lower foreign interest rates (relative to Australia) both raise demand for $A, lifting the trade-weighted index."}, {"id": "2019-Q19", "year": 2019, "n": 19, "topic": "Global Economy", "subs": ["Protection"], "img": "2019_q19.png", "w": 1020, "h": 325, "ans": ["C"], "expl": "The equivalent tariff raises the price to where imports equal 20,000 units; tariff revenue = tariff x import quantity = $20,000."}, {"id": "2019-Q20", "year": 2019, "n": 20, "topic": "Global Economy", "subs": ["Protection"], "img": "2019_q20.png", "w": 1020, "h": 296, "ans": ["D"], "expl": "The subsidy must lift domestic supply enough to meet all demand at the world price of $3; from the diagram that requires $4 per unit, eliminating imports."}, {"id": "2020-Q1", "year": 2020, "n": 1, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2020_q01.png", "w": 1020, "h": 240, "ans": ["A"], "expl": "The RBA's monetary policy targets price stability and full employment (along with the economic welfare of Australians)."}, {"id": "2020-Q2", "year": 2020, "n": 2, "topic": "Global Economy", "subs": ["Introduction to the global economy"], "img": "2020_q02.png", "w": 1020, "h": 268, "ans": ["C"], "expl": "The IMF promotes stability in global financial markets; the World Bank funds development and the WTO governs trade."}, {"id": "2020-Q3", "year": 2020, "n": 3, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2020_q03.png", "w": 1020, "h": 269, "ans": ["D"], "expl": "Under decentralised bargaining, pay and conditions are negotiated at the enterprise level, so contracts differ between workplaces."}, {"id": "2020-Q4", "year": 2020, "n": 4, "topic": "Global Economy", "subs": ["Globalisation and economic development"], "img": "2020_q04.png", "w": 1020, "h": 240, "ans": ["C"], "expl": "Developing economies typically have poor access to education and under-provide public goods, reflecting low incomes and weak institutions."}, {"id": "2020-Q5", "year": 2020, "n": 5, "topic": "Global Economy", "subs": ["Protection"], "img": "2020_q05.png", "w": 1020, "h": 352, "ans": ["A"], "expl": "A smaller quota cuts imports and supply, raising the domestic wheat price; local producers gain while government and foreign-exporter revenue fall."}, {"id": "2020-Q6", "year": 2020, "n": 6, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2020_q06.png", "w": 1020, "h": 562, "ans": ["B"], "expl": "Terms of trade = export price index / import price index x 100 = 80/160 x 100 = 50, down from 80 - a decrease."}, {"id": "2020-Q7", "year": 2020, "n": 7, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2020_q07.png", "w": 1020, "h": 297, "ans": ["B", "C"], "expl": "Selling the marketing rights (a non-produced, non-financial asset) is a capital-account transaction; NESA accepted both B and C."}, {"id": "2020-Q8", "year": 2020, "n": 8, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2020_q08.png", "w": 1020, "h": 240, "ans": ["C"], "expl": "Hidden (discouraged) unemployed give up looking and leave the labour force, lowering the participation rate."}, {"id": "2020-Q9", "year": 2020, "n": 9, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2020_q09.png", "w": 1020, "h": 759, "ans": ["C"], "expl": "AD2 lies to the left (lower demand); a higher cash rate curbs spending and investment, shifting aggregate demand left."}, {"id": "2020-Q10", "year": 2020, "n": 10, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2020_q10.png", "w": 1020, "h": 779, "ans": ["D"], "expl": "Higher consumer confidence lifts demand and the CPI, while a stronger trading-partner currency makes Australian exports cheaper, boosting jobs and cutting unemployment."}, {"id": "2020-Q11", "year": 2020, "n": 11, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2020_q11.png", "w": 1020, "h": 520, "ans": ["B"], "expl": "A depreciation follows an expansionary (rate-cutting) stance, and it raises the local-currency cost of servicing foreign borrowing."}, {"id": "2020-Q12", "year": 2020, "n": 12, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2020_q12.png", "w": 1020, "h": 579, "ans": ["C"], "expl": "At the NAIRU, faster growth from higher aggregate demand cannot cut structural unemployment further, but it can reduce underemployment (fuller hours)."}, {"id": "2020-Q13", "year": 2020, "n": 13, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2020_q13.png", "w": 1020, "h": 325, "ans": ["D"], "expl": "Higher returns on Australians' overseas investments (a primary income credit) improve the income balance and help reduce net foreign liabilities relative to GDP."}, {"id": "2020-Q14", "year": 2020, "n": 14, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2020_q14.png", "w": 1020, "h": 441, "ans": ["B"], "expl": "A $3.5bn current account surplus must be offset by a $3.5bn capital and financial account deficit; the swing from +$10.6bn to -$3.5bn is a change of $14.1bn."}, {"id": "2020-Q15", "year": 2020, "n": 15, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2020_q15.png", "w": 1020, "h": 324, "ans": ["B"], "expl": "A short-term petrol oversupply lowers volatile fuel prices, pulling headline inflation below the underlying rate."}, {"id": "2020-Q16", "year": 2020, "n": 16, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2020_q16.png", "w": 1020, "h": 574, "ans": ["D"], "expl": "Nominal GDP and prices both rose 5%, so real GDP is unchanged; the rise is purely higher costs and prices, not more output."}, {"id": "2020-Q17", "year": 2020, "n": 17, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2020_q17.png", "w": 1020, "h": 325, "ans": ["C"], "expl": "k = 25/10 = 2.5 = 1/(1-MPC), so MPC = 0.6."}, {"id": "2020-Q18", "year": 2020, "n": 18, "topic": "Global Economy", "subs": ["Protection"], "img": "2020_q18.png", "w": 1020, "h": 503, "ans": ["A"], "expl": "Domestic production falls from 30,000 to 25,000 (35,000 consumed minus 10,000 imported) - down 5,000 kg; tariff revenue = $5 x 10,000 = $50,000."}, {"id": "2020-Q19", "year": 2020, "n": 19, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2020_q19.png", "w": 1020, "h": 650, "ans": ["C"], "expl": "A higher Australian cash rate relative to the US attracts funds to Australia, depreciating the US dollar against the $A."}, {"id": "2020-Q20", "year": 2020, "n": 20, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2020_q20.png", "w": 1020, "h": 843, "ans": ["D"], "expl": "The above-equilibrium minimum wage creates unemployment; those who lose jobs have no wage income, worsening inequality - the Lorenz curve shifts outward."}, {"id": "2021-Q1", "year": 2021, "n": 1, "topic": "Global Economy", "subs": ["Introduction to the global economy"], "img": "2021_q01.png", "w": 1020, "h": 240, "ans": ["A"], "expl": "The WTO administers trade rules and resolves disputes between members; it does not set tariffs or lend money."}, {"id": "2021-Q2", "year": 2021, "n": 2, "topic": "Global Economy", "subs": ["Globalisation and economic development"], "img": "2021_q02.png", "w": 1020, "h": 324, "ans": ["B"], "expl": "High per-capita income and a diversified export base characterise an advanced economy."}, {"id": "2021-Q3", "year": 2021, "n": 3, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2021_q03.png", "w": 1020, "h": 241, "ans": ["C"], "expl": "The National Minimum Wage is set separately by the Fair Work Commission; it is not one of the ten National Employment Standards."}, {"id": "2021-Q4", "year": 2021, "n": 4, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2021_q04.png", "w": 1020, "h": 395, "ans": ["A"], "expl": "A downturn lowers incomes and tax revenue, automatically widening the budget deficit."}, {"id": "2021-Q5", "year": 2021, "n": 5, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2021_q05.png", "w": 1020, "h": 241, "ans": ["B"], "expl": "The structural component reflects discretionary (deliberate) policy decisions; the cyclical component reflects the business cycle."}, {"id": "2021-Q6", "year": 2021, "n": 6, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2021_q06.png", "w": 1020, "h": 286, "ans": ["B"], "expl": "A consumption tax is regressive, hitting low incomes harder and increasing inequality (a higher Gini coefficient)."}, {"id": "2021-Q7", "year": 2021, "n": 7, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2021_q07.png", "w": 1020, "h": 240, "ans": ["D"], "expl": "As incomes rise, progressive tax pushes people into higher brackets, automatically restraining demand - an automatic stabiliser (bracket creep)."}, {"id": "2021-Q8", "year": 2021, "n": 8, "topic": "Global Economy", "subs": ["Protection"], "img": "2021_q08.png", "w": 1020, "h": 240, "ans": ["C"], "expl": "Larger quotas and lower tariffs both reduce barriers, increasing free trade."}, {"id": "2021-Q9", "year": 2021, "n": 9, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2021_q09.png", "w": 1020, "h": 324, "ans": ["B"], "expl": "Cheaper imports reduce import spending and a depreciation boosts exports, together improving the trade balance and moving the current account toward surplus."}, {"id": "2021-Q10", "year": 2021, "n": 10, "topic": "Economic Policies", "subs": ["Fiscal policy", "Monetary policy"], "img": "2021_q10.png", "w": 1020, "h": 706, "ans": ["D"], "expl": "Higher taxation and a higher cash rate are both contractionary, dampening an overheating economy as GDP moves from X to Y."}, {"id": "2021-Q11", "year": 2021, "n": 11, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2021_q11.png", "w": 1020, "h": 512, "ans": ["B"], "expl": "Inflation for Year 3 = (148-140)/140 x 100 = 5.7%."}, {"id": "2021-Q12", "year": 2021, "n": 12, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2021_q12.png", "w": 1020, "h": 391, "ans": ["D"], "expl": "A higher MPS means more leakage and a smaller multiplier (k=1/MPS), so equilibrium national income falls."}, {"id": "2021-Q13", "year": 2021, "n": 13, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2021_q13.png", "w": 1020, "h": 241, "ans": ["C"], "expl": "Public goods are non-excludable, so people can benefit without paying directly - the free-rider problem."}, {"id": "2021-Q14", "year": 2021, "n": 14, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2021_q14.png", "w": 1020, "h": 296, "ans": ["C"], "expl": "Workers' remittances sent abroad are current transfers - a debit in the secondary income account."}, {"id": "2021-Q15", "year": 2021, "n": 15, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2021_q15.png", "w": 1020, "h": 268, "ans": ["A"], "expl": "A higher minimum wage draws more people to seek work (participation up) but reduces labour demand, so some cannot find jobs (unemployment up)."}, {"id": "2021-Q16", "year": 2021, "n": 16, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2021_q16.png", "w": 1020, "h": 297, "ans": ["D"], "expl": "Faster travel is a direct private benefit to the road's users, not a spillover to third parties, so it is not an externality."}, {"id": "2021-Q17", "year": 2021, "n": 17, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2021_q17.png", "w": 1020, "h": 611, "ans": ["A"], "expl": "Unemployment fell (2.5/13.6=18% to 2.3/14.3=16%) while participation rose (13.6/25=54% to 14.3/26=55%)."}, {"id": "2021-Q18", "year": 2021, "n": 18, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2021_q18.png", "w": 1020, "h": 675, "ans": ["D"], "expl": "BOGS = exports - imports = 125-110 = +$15bn. Current account = 15-30-20 = -35; with the capital account -45, the financial account Z must be +$80bn."}, {"id": "2021-Q19", "year": 2021, "n": 19, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2021_q19.png", "w": 1020, "h": 350, "ans": ["B"], "expl": "The currency has risen above the band, so the bank eases - cutting the cash rate reduces demand for the currency, depreciating it back into range."}, {"id": "2021-Q20", "year": 2021, "n": 20, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2021_q20.png", "w": 1020, "h": 541, "ans": ["C"], "expl": "Real GDP = nominal/CPI x 100: Year 2 = 217.4, Year 3 = 240.0, so real growth = (240-217.4)/217.4 = 10.4%."}, {"id": "2022-Q1", "year": 2022, "n": 1, "topic": "Global Economy", "subs": ["Introduction to the global economy"], "img": "2022_q01.png", "w": 1020, "h": 240, "ans": ["C"], "expl": "The IMF promotes global financial stability; the World Bank funds development, the UN is broader and the OECD is a policy forum."}, {"id": "2022-Q2", "year": 2022, "n": 2, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2022_q02.png", "w": 1020, "h": 419, "ans": ["A"], "expl": "Having stopped looking for work, this person is a discouraged worker - counted as neither unemployed nor in the labour force."}, {"id": "2022-Q3", "year": 2022, "n": 3, "topic": "Global Economy", "subs": ["Globalisation and economic development"], "img": "2022_q03.png", "w": 1020, "h": 240, "ans": ["D"], "expl": "A declining role for transnational corporations would slow globalisation; migration, financial flows and lower protection all speed it up."}, {"id": "2022-Q4", "year": 2022, "n": 4, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2022_q04.png", "w": 1020, "h": 240, "ans": ["D"], "expl": "Full employment is a low unemployment rate consistent with non-accelerating inflation (the NAIRU) - not zero, and including frictional and structural unemployment."}, {"id": "2022-Q5", "year": 2022, "n": 5, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2022_q05.png", "w": 1020, "h": 240, "ans": ["B"], "expl": "A depreciation makes imports dearer, raising imported and cost inflation."}, {"id": "2022-Q6", "year": 2022, "n": 6, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2022_q06.png", "w": 1020, "h": 297, "ans": ["C"], "expl": "Tradeable water permits use price signals and markets to allocate a scarce resource - a market-based environmental policy."}, {"id": "2022-Q7", "year": 2022, "n": 7, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2022_q07.png", "w": 1020, "h": 296, "ans": ["B", "D"], "expl": "A minority shareholding is portfolio investment; NESA accepted both B and D."}, {"id": "2022-Q8", "year": 2022, "n": 8, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2022_q08.png", "w": 1020, "h": 657, "ans": ["A"], "expl": "The diagram shows a fall in aggregate demand; higher exports would raise AD, so that cannot be the cause. Lower investment or government spending, or higher imports, would."}, {"id": "2022-Q9", "year": 2022, "n": 9, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2022_q09.png", "w": 1020, "h": 240, "ans": ["B"], "expl": "Ending a wage subsidy cuts government spending, helping to reduce the budget deficit."}, {"id": "2022-Q10", "year": 2022, "n": 10, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2022_q10.png", "w": 1020, "h": 296, "ans": ["B"], "expl": "Blocking a merger is regulation used to preserve competition in a product (goods and services) market."}, {"id": "2022-Q11", "year": 2022, "n": 11, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2022_q11.png", "w": 1020, "h": 696, "ans": ["A"], "expl": "Current account = net goods 80.5 + net services 10.2 - primary 63.8 - secondary 4.3 = +$22.6bn."}, {"id": "2022-Q12", "year": 2022, "n": 12, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2022_q12.png", "w": 1020, "h": 268, "ans": ["D"], "expl": "Raising the regressive GST from 10% to 15% hits low incomes harder, increasing the Gini coefficient and income inequality."}, {"id": "2022-Q13", "year": 2022, "n": 13, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2022_q13.png", "w": 1020, "h": 240, "ans": ["B"], "expl": "A larger childcare subsidy lowers a barrier to work, drawing more people (often parents) into the labour force - a higher participation rate."}, {"id": "2022-Q14", "year": 2022, "n": 14, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2022_q14.png", "w": 1020, "h": 388, "ans": ["D"], "expl": "Aggregate demand and aggregate supply both shifting left unambiguously reduce output, lowering GDP."}, {"id": "2022-Q15", "year": 2022, "n": 15, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2022_q15.png", "w": 1020, "h": 269, "ans": ["D"], "expl": "Vocational training raises skills and job-matching, lowering structural unemployment and the NAIRU."}, {"id": "2022-Q16", "year": 2022, "n": 16, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2022_q16.png", "w": 1020, "h": 635, "ans": ["C"], "expl": "Real GDP = nominal/CPI x 100. Country C = 23/118 x 100 = 19.5, below its Year 1 real GDP of $20bn - negative growth."}, {"id": "2022-Q17", "year": 2022, "n": 17, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2022_q17.png", "w": 1020, "h": 498, "ans": ["B"], "expl": "MPC = 320/400 = 0.8, so k = 5. A $30m fall in investment lowers income by $150m, from $2400m to $2250m."}, {"id": "2022-Q18", "year": 2022, "n": 18, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2022_q18.png", "w": 1020, "h": 1334, "ans": ["A"], "expl": "The terms of trade rise from 115/105=109.5 to 110/85=129.4 as import prices fall; a reduction in foreign labour costs lowering import prices fits."}, {"id": "2022-Q19", "year": 2022, "n": 19, "topic": "Global Economy", "subs": ["Protection"], "img": "2022_q19.png", "w": 1020, "h": 268, "ans": ["A"], "expl": "Lowering the tariff from $6 to $4 (price $12) widens imports enough that tariff revenue (tariff x imports) rises by $80 million."}, {"id": "2022-Q20", "year": 2022, "n": 20, "topic": "Global Economy", "subs": ["Protection"], "img": "2022_q20.png", "w": 1020, "h": 269, "ans": ["C"], "expl": "Foreign producers receive the world price ($8); the larger import quantity after the tariff cut raises their revenue by $160 million."}, {"id": "2023-Q1", "year": 2023, "n": 1, "topic": "Global Economy", "subs": ["Introduction to the global economy"], "img": "2023_q01.png", "w": 1020, "h": 268, "ans": ["B"], "expl": "The OECD promotes sustainable growth and employment among its member countries; it does not lend or provide crisis liquidity."}, {"id": "2023-Q2", "year": 2023, "n": 2, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2023_q02.png", "w": 1020, "h": 240, "ans": ["B"], "expl": "Mining is Australia's largest export industry by value."}, {"id": "2023-Q3", "year": 2023, "n": 3, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2023_q03.png", "w": 1020, "h": 296, "ans": ["C"], "expl": "Raising the school leaving age keeps more young people out of the labour force, lowering the participation rate."}, {"id": "2023-Q4", "year": 2023, "n": 4, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2023_q04.png", "w": 1020, "h": 751, "ans": ["A"], "expl": "A cut in taxation lifts disposable income and spending, shifting aggregate demand right (AD1 to AD2)."}, {"id": "2023-Q5", "year": 2023, "n": 5, "topic": "Global Economy", "subs": ["Protection"], "img": "2023_q05.png", "w": 1020, "h": 411, "ans": ["B"], "expl": "The tariff raises consumer prices in Country A and, by cutting Country B's exports, lowers producer incomes in Country B."}, {"id": "2023-Q6", "year": 2023, "n": 6, "topic": "Global Economy", "subs": ["Trade, financial flows and foreign investment"], "img": "2023_q06.png", "w": 1020, "h": 240, "ans": ["C"], "expl": "Freer trade encourages specialisation and efficiency, lifting long-run real GDP; tariff revenue and trade with non-members fall."}, {"id": "2023-Q7", "year": 2023, "n": 7, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2023_q07.png", "w": 1020, "h": 240, "ans": ["A"], "expl": "Clean air is non-excludable and non-rival - a public good. The other options can be priced or exclude users."}, {"id": "2023-Q8", "year": 2023, "n": 8, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2023_q08.png", "w": 1020, "h": 354, "ans": ["D"], "expl": "Moving from a $10m surplus to a $20m surplus withdraws more demand - a contractionary fiscal stance."}, {"id": "2023-Q9", "year": 2023, "n": 9, "topic": "Global Economy", "subs": ["Globalisation and economic development"], "img": "2023_q09.png", "w": 1020, "h": 512, "ans": ["C"], "expl": "A rising HDI reflects development - greater access to transport, communication, health and education."}, {"id": "2023-Q10", "year": 2023, "n": 10, "topic": "Global Economy", "subs": ["Protection"], "img": "2023_q10.png", "w": 1020, "h": 296, "ans": ["A"], "expl": "A country cuts an import quota mainly to protect domestic producers, for example against dumping."}, {"id": "2023-Q11", "year": 2023, "n": 11, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2023_q11.png", "w": 1020, "h": 718, "ans": ["C"], "expl": "Fewer imports means fewer $A supplied to buy foreign currency, shifting the supply of $A left (S1 to S2) and appreciating the dollar."}, {"id": "2023-Q12", "year": 2023, "n": 12, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2023_q12.png", "w": 1020, "h": 334, "ans": ["D"], "expl": "A lower cash rate cheapens credit, lifting both asset prices and business investment."}, {"id": "2023-Q13", "year": 2023, "n": 13, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2023_q13.png", "w": 1020, "h": 512, "ans": ["D"], "expl": "Net foreign debt = 1200-300 = $900bn; net foreign equity = 500-200 = $300bn; net foreign liabilities = $1200bn."}, {"id": "2023-Q14", "year": 2023, "n": 14, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2023_q14.png", "w": 1020, "h": 296, "ans": ["A"], "expl": "Taxing a negative externality of production raises the firm's marginal private cost so it reflects the true social cost, cutting output to the efficient level."}, {"id": "2023-Q15", "year": 2023, "n": 15, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2023_q15.png", "w": 1020, "h": 360, "ans": ["A"], "expl": "A deterioration in the terms of trade needs export prices to fall relative to import prices - a 10% fall in export prices with a 20% rise in import prices."}, {"id": "2023-Q16", "year": 2023, "n": 16, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2023_q16.png", "w": 1020, "h": 731, "ans": ["B"], "expl": "With the fixed rate below the market equilibrium there is excess demand for the currency, so the central bank sells its own currency and buys foreign currency to hold the rate."}, {"id": "2023-Q17", "year": 2023, "n": 17, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2023_q17.png", "w": 1020, "h": 578, "ans": ["C"], "expl": "Contribution = weight x price rise. Health (20x25=500) exceeds housing (16x30=480), food and education, so it adds most to inflation."}, {"id": "2023-Q18", "year": 2023, "n": 18, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2023_q18.png", "w": 1020, "h": 561, "ans": ["C"], "expl": "MPS = 20/100 = 0.2, so k = 5. A $50m rise in spending adds $250m, lifting income from $1100m to $1350m."}, {"id": "2023-Q19", "year": 2023, "n": 19, "topic": "Global Economy", "subs": ["Protection"], "img": "2023_q19.png", "w": 1020, "h": 825, "ans": ["B"], "expl": "The subsidy lifts domestic supply so imports fall by 50,000; from the diagram that requires $10 per T-shirt."}, {"id": "2023-Q20", "year": 2023, "n": 20, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2023_q20.png", "w": 1020, "h": 691, "ans": ["D"], "expl": "The TWI weights currencies by trade share. Depreciating against the higher-weighted yen (13%) while appreciating against the lower-weighted US dollar (8%) lowers the index."}, {"id": "2024-Q1", "year": 2024, "n": 1, "topic": "Global Economy", "subs": ["Introduction to the global economy"], "img": "2024_q01.png", "w": 1020, "h": 276, "ans": ["A"], "expl": "The World Bank's main role is improving quality of life in developing countries through development financing."}, {"id": "2024-Q2", "year": 2024, "n": 2, "topic": "Economic Policies", "subs": ["Microeconomic and labour market reform"], "img": "2024_q02.png", "w": 1020, "h": 248, "ans": ["C"], "expl": "A centralised system sets uniform minimum wages and conditions, providing a safety net for workers."}, {"id": "2024-Q3", "year": 2024, "n": 3, "topic": "Economic Policies", "subs": ["Objectives of economic policy"], "img": "2024_q03.png", "w": 1020, "h": 248, "ans": ["A"], "expl": "In the short run, stimulating full employment tends to raise inflation, so price stability and full employment conflict - the Phillips-curve trade-off."}, {"id": "2024-Q4", "year": 2024, "n": 4, "topic": "Global Economy", "subs": ["Protection"], "img": "2024_q04.png", "w": 1020, "h": 248, "ans": ["C"], "expl": "Free trade can expose domestic producers to dumping (imports sold below cost). The other options are benefits of free trade."}, {"id": "2024-Q5", "year": 2024, "n": 5, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2024_q05.png", "w": 1020, "h": 304, "ans": ["D"], "expl": "A minority (5%) holding is portfolio investment; the inflow of foreign capital is a credit on the financial account."}, {"id": "2024-Q6", "year": 2024, "n": 6, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2024_q06.png", "w": 1020, "h": 508, "ans": ["D"], "expl": "Participation rate = labour force (7m employed + 2m unemployed = 9m) / working-age population (11m) = 82%."}, {"id": "2024-Q7", "year": 2024, "n": 7, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2024_q07.png", "w": 1020, "h": 495, "ans": ["C"], "expl": "MPS = 40/100 = 0.4, so MPC = 1 - 0.4 = 0.6."}, {"id": "2024-Q8", "year": 2024, "n": 8, "topic": "Economic Policies", "subs": ["Monetary policy"], "img": "2024_q08.png", "w": 1020, "h": 248, "ans": ["B"], "expl": "Monetary policy can be changed quickly by the RBA, giving it the shortest implementation lag."}, {"id": "2024-Q9", "year": 2024, "n": 9, "topic": "Economic Issues", "subs": ["Unemployment"], "img": "2024_q09.png", "w": 1020, "h": 276, "ans": ["D"], "expl": "Better job-search agencies match workers to jobs faster, reducing frictional (between-jobs) unemployment."}, {"id": "2024-Q10", "year": 2024, "n": 10, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2024_q10.png", "w": 1020, "h": 342, "ans": ["B"], "expl": "Raising the cash rate and buying $A in the foreign exchange market both increase demand for the dollar, appreciating it."}, {"id": "2024-Q11", "year": 2024, "n": 11, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2024_q11.png", "w": 1020, "h": 658, "ans": ["A"], "expl": "Cheaper tertiary education raises skills and productivity, lowering costs and shifting aggregate supply right (AS1 to AS2)."}, {"id": "2024-Q12", "year": 2024, "n": 12, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2024_q12.png", "w": 1020, "h": 730, "ans": ["D"], "expl": "With a floating rate the current account (-$90bn, offsetting +$90bn on capital+financial) = X-36+12-120-6, so exports = $60bn."}, {"id": "2024-Q13", "year": 2024, "n": 13, "topic": "Australia & Global Economy", "subs": ["Protection in Australia"], "img": "2024_q13.png", "w": 1020, "h": 447, "ans": ["C"], "expl": "Local content rules substitute domestic production for imports, cutting imports and raising short-term local employment."}, {"id": "2024-Q14", "year": 2024, "n": 14, "topic": "Economic Issues", "subs": ["Distribution of income and wealth"], "img": "2024_q14.png", "w": 1020, "h": 426, "ans": ["A"], "expl": "Cutting childcare subsidies and lowering the tax-free threshold both reduce low-income households' disposable income, raising inequality."}, {"id": "2024-Q15", "year": 2024, "n": 15, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2024_q15.png", "w": 1020, "h": 342, "ans": ["B"], "expl": "Interest rates (cyclical) affect income servicing costs, while chronically low national saving (structural) drives reliance on foreign capital and its income outflow."}, {"id": "2024-Q16", "year": 2024, "n": 16, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2024_q16.png", "w": 1020, "h": 332, "ans": ["D"], "expl": "A cyclone spikes volatile fruit prices, lifting headline inflation above the steadier underlying rate."}, {"id": "2024-Q17", "year": 2024, "n": 17, "topic": "Australia & Global Economy", "subs": ["Exchange rates"], "img": "2024_q17.png", "w": 1020, "h": 398, "ans": ["C"], "expl": "Dearer imported inputs worsen the trade balance (depreciation) and raise business costs, pushing domestic prices higher (imported cost inflation)."}, {"id": "2024-Q18", "year": 2024, "n": 18, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2024_q18.png", "w": 1020, "h": 641, "ans": ["C"], "expl": "The current account deficit falls from 35/1200 = 2.9% to 36/1250 = 2.88% of GDP - a smaller deficit relative to GDP, improving external stability."}, {"id": "2024-Q19", "year": 2024, "n": 19, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2024_q19.png", "w": 1020, "h": 481, "ans": ["D"], "expl": "Weaker global demand for exports lowers export prices (the terms of trade) and demand for the currency (the trade-weighted index)."}, {"id": "2024-Q20", "year": 2024, "n": 20, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2024_q20.png", "w": 1020, "h": 495, "ans": ["B"], "expl": "Inflation = (120-110)/110 = 9.1%; real GDP = nominal/CPI: 545.5 to 562.5, a 3.1% real growth rate."}, {"id": "2025-Q1", "year": 2025, "n": 1, "topic": "Global Economy", "subs": ["Introduction to the global economy"], "img": "2025_q01.png", "w": 1020, "h": 304, "ans": ["A"], "expl": "Sharing a common currency is a monetary union (like the euro area)."}, {"id": "2025-Q2", "year": 2025, "n": 2, "topic": "Global Economy", "subs": ["Globalisation and economic development"], "img": "2025_q02.png", "w": 1020, "h": 241, "ans": ["C"], "expl": "Cheaper energy lowers transport and production costs, accelerating global trade and integration."}, {"id": "2025-Q3", "year": 2025, "n": 3, "topic": "Global Economy", "subs": ["Globalisation and economic development"], "img": "2025_q03.png", "w": 1020, "h": 555, "ans": ["D"], "expl": "Developing economies have low literacy (indicator X), while advanced economies have high life expectancy (indicator Y)."}, {"id": "2025-Q4", "year": 2025, "n": 4, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2025_q04.png", "w": 1020, "h": 269, "ans": ["B"], "expl": "In a downturn, spending falls, so indirect (GST and excise) tax revenue decreases; unemployment benefits and borrowing rise."}, {"id": "2025-Q5", "year": 2025, "n": 5, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2025_q05.png", "w": 1020, "h": 241, "ans": ["B"], "expl": "You pay a fare (excludable by price) and a full seat denies another rider (rival), so public transport is a private good."}, {"id": "2025-Q6", "year": 2025, "n": 6, "topic": "Economic Policies", "subs": ["Objectives of economic policy"], "img": "2025_q06.png", "w": 1020, "h": 241, "ans": ["C"], "expl": "Macroeconomic policy (fiscal and monetary) stabilises the business cycle by managing aggregate demand; productivity and supply are microeconomic aims."}, {"id": "2025-Q7", "year": 2025, "n": 7, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2025_q07.png", "w": 1020, "h": 326, "ans": ["D"], "expl": "k = 50/10 = 5 = 1/(1-MPC), so MPC = 0.8."}, {"id": "2025-Q8", "year": 2025, "n": 8, "topic": "Global Economy", "subs": ["Globalisation and economic development"], "img": "2025_q08.png", "w": 1020, "h": 241, "ans": ["D"], "expl": "A regional business cycle arises when economic activity is integrated across neighbouring countries, synchronising their cycles."}, {"id": "2025-Q9", "year": 2025, "n": 9, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2025_q09.png", "w": 1020, "h": 670, "ans": ["C"], "expl": "Injections (G+I+X = 160) exceed leakages (S+T+M = 130), so the economy is expanding."}, {"id": "2025-Q10", "year": 2025, "n": 10, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2025_q10.png", "w": 1020, "h": 269, "ans": ["B"], "expl": "Unconditional aid is a current transfer; when Australia gives it, it is a debit in the current account (secondary income)."}, {"id": "2025-Q11", "year": 2025, "n": 11, "topic": "Economic Policies", "subs": ["Fiscal policy"], "img": "2025_q11.png", "w": 1020, "h": 241, "ans": ["A"], "expl": "Automatic stabilisers - taxes and welfare moving with the cycle - drive the cyclical component of the budget."}, {"id": "2025-Q12", "year": 2025, "n": 12, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2025_q12.png", "w": 1020, "h": 269, "ans": ["A"], "expl": "An emissions trading scheme prices emissions and lets firms trade permits, using market forces. Bans, targeted taxes and fines are more direct."}, {"id": "2025-Q13", "year": 2025, "n": 13, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2025_q13.png", "w": 1020, "h": 769, "ans": ["B"], "expl": "Current account = (150-130)+(60-50)-50+10 = -$10bn; with the capital account +$70bn, the financial account must be -$60bn to balance."}, {"id": "2025-Q14", "year": 2025, "n": 14, "topic": "Economic Issues", "subs": ["Inflation"], "img": "2025_q14.png", "w": 1020, "h": 582, "ans": ["A"], "expl": "Drought spikes volatile food prices (headline up), while lower freight costs ease broad-based underlying inflation."}, {"id": "2025-Q15", "year": 2025, "n": 15, "topic": "Economic Issues", "subs": ["Economic growth"], "img": "2025_q15.png", "w": 1020, "h": 489, "ans": ["A"], "expl": "Real GDP = nominal/CPI x 100: Year 1 = 20, Year 2 = 20 - so real growth is 0%."}, {"id": "2025-Q16", "year": 2025, "n": 16, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2025_q16.png", "w": 1020, "h": 559, "ans": ["C"], "expl": "Net foreign equity = 3.0-1.2 = $1.8m; net foreign debt = 1.8-0.5 = $1.3m; net foreign liabilities = $3.1m."}, {"id": "2025-Q17", "year": 2025, "n": 17, "topic": "Australia & Global Economy", "subs": ["Protection in Australia"], "img": "2025_q17.png", "w": 1020, "h": 808, "ans": ["B"], "expl": "A smaller quota lets in fewer imports, reducing supply and raising the price from its current level to P2 (still below the no-trade price)."}, {"id": "2025-Q18", "year": 2025, "n": 18, "topic": "Global Economy", "subs": ["Protection"], "img": "2025_q18.png", "w": 1020, "h": 814, "ans": ["B"], "expl": "Foreign producers receive the world price ($20). The tariff cuts the import volume, reducing their revenue by $4000."}, {"id": "2025-Q19", "year": 2025, "n": 19, "topic": "Australia & Global Economy", "subs": ["Australia's trade and financial flows"], "img": "2025_q19.png", "w": 1020, "h": 583, "ans": ["D"], "expl": "Export price index = terms of trade x import price index / 100. Year 1 = 110x100/100 = 110; Year 2 = 90x110/100 = 99."}, {"id": "2025-Q20", "year": 2025, "n": 20, "topic": "Economic Issues", "subs": ["Environmental sustainability"], "img": "2025_q20.png", "w": 1020, "h": 751, "ans": ["D"], "expl": "The corrective tax equals the external cost - the vertical gap between the social and private cost curves, shown as P1 - P3."}];
